arguments.argument:
if global.gamePaused=false
{
  image_angle=direction
  speed=bulletSpeed
  dist=point_distance(x,y,xstart,ystart)
  if dist>32
  {
    if isCollisionTop(1)
      bBlownUp=true
    if isCollisionBottom(1)
      bBlownUp=true
    if isCollisionLeft(1)
      bBlownUp=true
    if isCollisionRight(1)
      bBlownUp=true
    
    if bBlownUp=true
      instance_destroy()
  }
}
else
  speed=0
